let WhitelistedGCS = _GetWatchlist('C2_Whitelisted_GCS_List');
let KnownIPs = dynamic(["10.50.0.10"]);
let lookback = 1h;
let baselineWindow = 24h;
let dropThreshold = 100;
// [블록 A] 비인가 GCS 명령
let UnauthorizedCmd =
    UAVOperator_CL
    | where TimeGenerated > ago(lookback)
    | join kind=leftanti (
        WhitelistedGCS
        | project UAVId = UAVId_s, SourceSystemId = toint(SystemId_d)
    ) on UAVId, SourceSystemId
    | extend TriggerReason = "Unauthorized_GCS_Command"
    | extend DetectionDetail = strcat(
        "SourceSystemId:", SourceSystemId,
        "|Action:", ActionName,
        "|Command:", Command
    )
    | project TimeGenerated, UAVId, TriggerReason, DetectionDetail;
// [블록 B] 링크 드롭 급증 (재밍 지표)
let LinkDrop =
    UAVDatalink_CL
    | where TimeGenerated > ago(lookback)
    | order by TimeGenerated asc
    | extend PrevDropped = prev(RxDropped)
    | extend DroppedDelta = RxDropped - PrevDropped
    | where isnotnull(DroppedDelta) and DroppedDelta > dropThreshold
    | extend UAVId = "MPD-001"
    | extend TriggerReason = "Datalink_RxDrop_Spike"
    | extend DetectionDetail = strcat(
        "RxDropped:", RxDropped,
        "|Delta:", DroppedDelta,
        "|Container:", ContainerName
    )
    | project TimeGenerated, UAVId, TriggerReason, DetectionDetail;
// [블록 C] 5790 포트 비인가 접속 (MAVLink 평문 인젝션 채널)
let UnauthorizedConn =
    UAVDatalinkConn_CL
    | where TimeGenerated > ago(lookback)
    | where LocalPort == 5790
    | where PeerIp !in (KnownIPs)
    | extend UAVId = "MPD-001"
    | extend TriggerReason = "Unauthorized_5790_Connection"
    | extend DetectionDetail = strcat(
        "PeerIp:", PeerIp,
        "|PeerPort:", PeerPort,
        "|State:", State
    )
    | project TimeGenerated, UAVId, TriggerReason, DetectionDetail;
UnauthorizedCmd
| union LinkDrop
| union UnauthorizedConn
| sort by TimeGenerated desc
